-- ============================================================
--  Online Food Delivery System — MySQL 8.x
--  Database : food_delivery_db
--  Charset  : utf8mb4 / utf8mb4_unicode_ci
--  Author   : FoodExpress Team
-- ============================================================

SET FOREIGN_KEY_CHECKS = 0;

DROP DATABASE IF EXISTS food_delivery_db;
CREATE DATABASE food_delivery_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE food_delivery_db;

CREATE TABLE users (
    user_id    INT            NOT NULL AUTO_INCREMENT,
    full_name  VARCHAR(100)   NOT NULL,
    email      VARCHAR(100)   NOT NULL,
    password   VARCHAR(255)   NOT NULL,
    phone      VARCHAR(15),
    address    TEXT,
    role       ENUM('CUSTOMER','ADMIN') NOT NULL DEFAULT 'CUSTOMER',
    created_at TIMESTAMP      NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (user_id),
    UNIQUE KEY uq_users_email (email)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE restaurants (
    restaurant_id INT             NOT NULL AUTO_INCREMENT,
    name          VARCHAR(150)    NOT NULL,
    description   TEXT,
    cuisine_type  VARCHAR(100),
    address       TEXT,
    phone         VARCHAR(15),
    image_url     VARCHAR(255),
    rating        DECIMAL(2,1)    NOT NULL DEFAULT 0.0,
    delivery_time VARCHAR(50),
    delivery_fee  DECIMAL(6,2)    NOT NULL DEFAULT 0.00,
    opening_hours VARCHAR(100)    DEFAULT '10:00 AM - 11:00 PM',
    min_order     DECIMAL(6,2)    DEFAULT 149.00,
    offer_banner  VARCHAR(255)    DEFAULT '🔥 Flat 20% OFF above ₹299',
    is_active     BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at    TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (restaurant_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE food_items (
    food_id       INT           NOT NULL AUTO_INCREMENT,
    restaurant_id INT           NOT NULL,
    name          VARCHAR(150)  NOT NULL,
    description   TEXT,
    price         DECIMAL(10,2) NOT NULL,
    category      VARCHAR(100),
    image_url     VARCHAR(255),
    is_available  BOOLEAN       NOT NULL DEFAULT TRUE,
    is_veg        BOOLEAN       NOT NULL DEFAULT TRUE,
    created_at    TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (food_id),
    CONSTRAINT fk_food_restaurant FOREIGN KEY (restaurant_id) REFERENCES restaurants (restaurant_id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE cart (
    cart_id    INT       NOT NULL AUTO_INCREMENT,
    user_id       INT       NOT NULL,
    restaurant_id INT       DEFAULT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (cart_id),
    UNIQUE KEY uq_cart_user (user_id),
    CONSTRAINT fk_cart_user FOREIGN KEY (user_id) REFERENCES users (user_id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE cart_items (
    cart_item_id INT NOT NULL AUTO_INCREMENT,
    cart_id      INT NOT NULL,
    food_id      INT NOT NULL,
    quantity     INT NOT NULL DEFAULT 1,
    PRIMARY KEY (cart_item_id),
    UNIQUE KEY unique_cart_food (cart_id, food_id),
    CONSTRAINT fk_cartitem_cart FOREIGN KEY (cart_id) REFERENCES cart (cart_id) ON DELETE CASCADE,
    CONSTRAINT fk_cartitem_food FOREIGN KEY (food_id) REFERENCES food_items (food_id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE orders (
    order_id         INT           NOT NULL AUTO_INCREMENT,
    user_id          INT           NOT NULL,
    total_amount     DECIMAL(10,2) NOT NULL,
    delivery_address TEXT          NOT NULL,
    status           VARCHAR(50)   NOT NULL DEFAULT 'PLACED',
    payment_method   ENUM('COD','UPI','CARD','WALLET') DEFAULT 'COD',
    gst_amount       DECIMAL(10,2) DEFAULT 0.00,
    delivery_fee     DECIMAL(10,2) DEFAULT 0.00,
    platform_fee     DECIMAL(10,2) DEFAULT 0.00,
    discount_amount  DECIMAL(10,2) DEFAULT 0.00,
    coupon_code      VARCHAR(50)   DEFAULT NULL,
    instructions     TEXT,
    created_at       TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at       TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (order_id),
    CONSTRAINT fk_order_user FOREIGN KEY (user_id) REFERENCES users (user_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE order_items (
    order_item_id INT           NOT NULL AUTO_INCREMENT,
    order_id      INT           NOT NULL,
    food_id       INT           NOT NULL,
    quantity      INT           NOT NULL,
    unit_price    DECIMAL(10,2) NOT NULL,
    PRIMARY KEY (order_item_id),
    CONSTRAINT fk_orderitem_order FOREIGN KEY (order_id) REFERENCES orders (order_id) ON DELETE CASCADE,
    CONSTRAINT fk_orderitem_food  FOREIGN KEY (food_id) REFERENCES food_items (food_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE payments (
    payment_id     INT           NOT NULL AUTO_INCREMENT,
    order_id       INT           NOT NULL,
    user_id        INT           NOT NULL,
    amount         DECIMAL(10,2) NOT NULL,
    payment_method ENUM('COD','UPI','CARD') NOT NULL,
    transaction_id VARCHAR(100),
    status         ENUM('PENDING','SUCCESS','FAILED') NOT NULL DEFAULT 'PENDING',
    paid_at        TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (payment_id),
    UNIQUE KEY uq_payment_order (order_id),
    CONSTRAINT fk_payment_order FOREIGN KEY (order_id) REFERENCES orders (order_id),
    CONSTRAINT fk_payment_user  FOREIGN KEY (user_id) REFERENCES users (user_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_food_restaurant ON food_items (restaurant_id);
CREATE INDEX idx_order_user      ON orders (user_id);
CREATE INDEX idx_order_status    ON orders (status);
CREATE INDEX idx_payment_order   ON payments (order_id);


CREATE TABLE coupons (
    coupon_id          INT NOT NULL AUTO_INCREMENT,
    code               VARCHAR(50) NOT NULL,
    description        VARCHAR(255),
    discount_type      ENUM('PERCENT','FLAT','FREE_DELIVERY') NOT NULL,
    discount_value     DECIMAL(10,2) NOT NULL DEFAULT 0.00,
    min_order_amount   DECIMAL(10,2) NOT NULL DEFAULT 0.00,
    max_discount       DECIMAL(10,2) NOT NULL DEFAULT 0.00,
    is_active          BOOLEAN NOT NULL DEFAULT TRUE,
    created_at         TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (coupon_id),
    UNIQUE KEY uq_coupons_code (code)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE reviews (
    review_id     INT NOT NULL AUTO_INCREMENT,
    order_id      INT NOT NULL,
    user_id       INT NOT NULL,
    restaurant_id INT NOT NULL,
    food_id       INT DEFAULT NULL,
    rating        INT NOT NULL,
    comment       TEXT,
    created_at    TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (review_id),
    CONSTRAINT fk_rev_order FOREIGN KEY (order_id) REFERENCES orders (order_id) ON DELETE CASCADE,
    CONSTRAINT fk_rev_user FOREIGN KEY (user_id) REFERENCES users (user_id) ON DELETE CASCADE,
    CONSTRAINT fk_rev_rest FOREIGN KEY (restaurant_id) REFERENCES restaurants (restaurant_id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;










SET FOREIGN_KEY_CHECKS = 1;
